{
  "grammar": [
    {
      "pattern": "Subject + 覺得 + [opinion clause]",
      "structure": ["Subject", "覺得", "opinion clause"],
      "explanation_en": "Use 覺得 to express a personal feeling or opinion, often based on subjective experience or emotion. It's softer than 認為 and common in daily conversation.",
      "title": "Using 覺得 for Personal Opinions",
      "meaning": "Expressing what you feel or think subjectively",
      "when_to_use": ["When sharing personal feelings or impressions", "When giving an opinion based on experience", "In casual conversations with friends or colleagues"],
      "when_not_to_use": ["When stating a fact or objective truth", "When making a formal or strong argument"],
      "pragmatic_notes": "In Taiwan, 覺得 is very common in daily speech. It's polite and non-confrontational, often used to soften opinions.",
      "word_order_notes": "Subject comes first, followed by 覺得, then the opinion clause. The opinion clause can be a full sentence.",
      "english_contrast": "English uses 'I think/feel that...' with similar word order, but 覺得 is more about feeling than logical thinking.",
      "korean_contrast": "Korean uses '나는 ...라고 생각해요' but 覺得 is closer to '느끼다' (feel) than '생각하다' (think).",
      "negative_examples": [
        {
          "text": "我覺得他不好吃。",
          "error": "This means 'I feel he is not delicious' – 覺得 should be used for opinions about people or things, not for eating."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我覺得他不好吃。",
          "error": "This means 'I feel he is not delicious' – 覺得 should be used for opinions about people or things, not for eating."
        }
      ],
      "transformation_drills": ["Change '我認為這個電影很好' to '我覺得這個電影很好'", "Change '我覺得他很高興' to a question: '你覺得他很高興嗎?'"],
      "production_drills": ["Say your opinion about a movie using 覺得", "Ask a friend what they think about a restaurant using 覺得"],
      "common_error_patterns": ["Using 覺得 for factual statements", "Forgetting the subject before 覺得"],
      "repair_feedback": {
        "word_order": "Remember: Subject + 覺得 + opinion. Don't put 覺得 at the end.",
        "politeness": "Using 覺得 is polite; avoid 認為 in casual settings as it can sound too formal.",
        "vocabulary": "Use 覺得 for feelings; use 認為 for reasoned opinions."
      }
    },
    {
      "pattern": "Subject + 認為 + [opinion clause]",
      "structure": ["Subject", "認為", "opinion clause"],
      "explanation_en": "Use 認為 to express a reasoned opinion or belief, often based on logic or analysis. It's more formal than 覺得 and common in discussions or debates.",
      "title": "Using 認為 for Reasoned Opinions",
      "meaning": "Expressing what you believe or think logically",
      "when_to_use": ["When stating a considered opinion", "In formal discussions or debates", "When you want to sound objective or analytical"],
      "when_not_to_use": ["For casual feelings or impressions", "When you want to be soft or polite"],
      "pragmatic_notes": "In Taiwan, 認為 is used in more serious contexts like work meetings or academic discussions. It implies confidence in your opinion.",
      "word_order_notes": "Subject + 認為 + opinion clause. The opinion clause can be a full sentence, similar to 覺得.",
      "english_contrast": "English 'I believe/consider that...' is similar, but 認為 is more about belief than feeling.",
      "korean_contrast": "Korean '나는 ...라고 생각합니다' matches 認為 well, both are formal and logical.",
      "negative_examples": [
        {
          "text": "我認為今天天氣很好。",
          "error": "This is correct but too formal for casual weather talk. Use 覺得 instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我認為今天天氣很好。",
          "error": "This is correct but too formal for casual weather talk. Use 覺得 instead."
        }
      ],
      "transformation_drills": ["Change '我覺得這個計畫不好' to '我認為這個計畫不好'", "Change '我認為他對' to a question: '你認為他對嗎?'"],
      "production_drills": ["State your opinion about a policy using 認為", "Ask a colleague's opinion on a project using 認為"],
      "common_error_patterns": ["Using 認為 for subjective feelings", "Overusing 認為 in casual conversation"],
      "repair_feedback": {
        "word_order": "Same as 覺得: Subject + 認為 + opinion.",
        "politeness": "認為 can sound too strong in casual settings; use 覺得 for softer opinions.",
        "vocabulary": "Use 認為 for logical beliefs; use 覺得 for feelings."
      }
    },
    {
      "pattern": "不一定 + [verb phrase]",
      "structure": ["不一定", "verb phrase"],
      "explanation_en": "Use 不一定 to express uncertainty or that something is not necessarily true. It means 'not necessarily' or 'maybe not'.",
      "title": "Using 不一定 for Uncertainty",
      "meaning": "Expressing that something is not necessarily the case",
      "when_to_use": ["When you want to say something might not be true", "When disagreeing gently with a generalization", "When expressing doubt or possibility"],
      "when_not_to_use": ["When you are certain about something", "When you want to say 'no' directly"],
      "pragmatic_notes": "In Taiwan, 不一定 is a polite way to disagree or express doubt without being confrontational. It's common in discussions.",
      "word_order_notes": "不一定 comes before the verb phrase. It can also be used alone as a response.",
      "english_contrast": "English 'not necessarily' is similar, but 不一定 is more common in daily speech.",
      "korean_contrast": "Korean '꼭 그렇지는 않다' matches 不一定 in meaning and politeness.",
      "negative_examples": [
        {
          "text": "不一定他來。",
          "error": "Word order is wrong. Should be '他不一定來' (He might not come)."
        }
      ],
      "incorrect_examples": [
        {
          "text": "不一定他來。",
          "error": "Word order is wrong. Should be '他不一定來' (He might not come)."
        }
      ],
      "transformation_drills": ["Change '他一定來' to '他不一定來'", "Change '這個電影很好' to '這個電影不一定很好'"],
      "production_drills": ["Say 'Not necessarily' in response to a statement", "Make a sentence about a friend's opinion using 不一定"],
      "common_error_patterns": ["Placing 不一定 after the verb", "Using 不一定 with 是 unnecessarily"],
      "repair_feedback": {
        "word_order": "Place 不一定 before the verb phrase, e.g., '他不一定去'.",
        "politeness": "不一定 is polite for disagreement; avoid using 不對 directly.",
        "vocabulary": "Use 不一定 for uncertainty; use 可能 for possibility."
      }
    }
  ]
}
